import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the quadratic formula?", a: "The quadratic formula solves equations in the form ax^2 + bx + c = 0. The formula is x = (-b +/- sqrt(b^2 - 4ac)) / 2a." },
  { q: "What is the discriminant and what does it tell you?", a: "The discriminant is b^2 - 4ac. If it is positive, there are two real roots. If it is zero, there is one repeated real root. If it is negative, the roots are complex." },
  { q: "How do you find the vertex of a parabola?", a: "For y = ax^2 + bx + c, the vertex x-coordinate is -b / 2a. Substitute that x-value into the equation to find the y-coordinate." },
  { q: "What does it mean when a quadratic has no real roots?", a: "No real roots means the parabola does not cross the x-axis. The roots still exist as complex numbers involving i, the imaginary unit." },
  { q: "When should you use the quadratic formula vs factoring?", a: "Factoring is fast when the quadratic has simple factors. The quadratic formula works for every quadratic equation, including equations that are difficult or impossible to factor neatly." },
];

const fmt = (value: number) => Number(value.toFixed(6)).toLocaleString();

export default function QuadraticFormulaCalculator() {
  const [a, setA] = useState(1);
  const [b, setB] = useState(-3);
  const [c, setC] = useState(2);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (a === 0) return { roots: "Not a quadratic equation", discriminant: "Invalid", vertex: "Invalid", description: "The value of a must not be zero.", step: "A quadratic equation needs a nonzero a coefficient." };
    const d = b * b - 4 * a * c;
    const vx = -b / (2 * a);
    const vy = a * vx * vx + b * vx + c;
    const opens = a > 0 ? "opens upward and has a minimum" : "opens downward and has a maximum";
    if (d >= 0) {
      const sqrtD = Math.sqrt(d);
      const x1 = (-b + sqrtD) / (2 * a);
      const x2 = (-b - sqrtD) / (2 * a);
      return { roots: d === 0 ? `x = ${fmt(x1)}` : `x = ${fmt(x1)} and x = ${fmt(x2)}`, discriminant: fmt(d), vertex: `(${fmt(vx)}, ${fmt(vy)})`, description: `The parabola ${opens}.`, step: `D = ${b}^2 - 4(${a})(${c}) = ${fmt(d)}. x = (-${b} +/- sqrt(${fmt(d)})) / (2 x ${a}).` };
    }
    const real = -b / (2 * a);
    const imaginary = Math.sqrt(Math.abs(d)) / Math.abs(2 * a);
    return { roots: `x = ${fmt(real)} +/- ${fmt(imaginary)}i`, discriminant: fmt(d), vertex: `(${fmt(vx)}, ${fmt(vy)})`, description: `The parabola ${opens} and has no real x-intercepts.`, step: `D = ${b}^2 - 4(${a})(${c}) = ${fmt(d)}. Because D is negative, the roots are complex.` };
  }, [a, b, c]);

  return (
    <>
      <SEOHead title="Free Quadratic Formula Calculator Online - Solve Any Quadratic Equation Instantly | CalcHive" description="Free online quadratic formula calculator. Solve any quadratic equation ax- + bx + c = 0 instantly with full step by step solution, both roots, discriminant and vertex. 100% free, no signup required." canonical="/quadratic-formula-calculator" keywords="free quadratic formula calculator, quadratic equation solver free online, solve quadratic equation free, ax2+bx+c calculator free, algebra quadratic calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Quadratic Formula Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this quadratic equation solver free online to solve ax^2 + bx + c = 0 with roots, discriminant, vertex, and steps.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="quad-a" className="text-sm font-semibold text-foreground block mb-2">a</label><input id="quad-a" type="number" inputMode="decimal" value={a} onChange={(event) => setA(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="quad-b" className="text-sm font-semibold text-foreground block mb-2">b</label><input id="quad-b" type="number" inputMode="decimal" value={b} onChange={(event) => setB(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="quad-c" className="text-sm font-semibold text-foreground block mb-2">c</label><input id="quad-c" type="number" inputMode="decimal" value={c} onChange={(event) => setC(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${a}-${b}-${c}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Roots</p><p className="text-3xl sm:text-4xl font-black text-white tracking-tight break-words" data-testid="result-roots">{result.roots}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Discriminant</p><p className="text-xl font-extrabold text-foreground">{result.discriminant}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Vertex</p><p className="text-xl font-extrabold text-foreground">{result.vertex}</p></div></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-sm text-foreground mb-2">{result.description}</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Solve Any Quadratic Equation for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a, b, and c from ax^2 + bx + c = 0. This free quadratic formula calculator applies the formula and returns real or complex roots.</p>
          <h2 className="text-2xl font-bold text-foreground">How the Quadratic Formula Works Step by Step</h2><p className="text-muted-foreground leading-relaxed">The calculator finds the discriminant first, then substitutes it into x = (-b +/- sqrt(b^2 - 4ac)) / 2a.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Algebra Quadratic Solver for Students</h2><p className="text-muted-foreground leading-relaxed">Use this solve quadratic equation free tool to check homework, understand graph behavior, and review vertex and discriminant results.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/quadratic-formula-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


